import { ToastType } from '../types';
import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';

export async function hideAllToastsInAllTabsByType(
  type: ToastType,
): Promise<void> {
  try {
    await messageDispatcher.send({
      action: Actions.HideAllToastsByType,
      payload: {
        type,
      },
    });
  } catch (error) {
    logger.error('toast: cannot close all toast in all tabs: ', error);
  }
}
