import { ToastInstance } from '../types';

/**
 * Централизованное хранилище всех активных toast экземпляров
 * Используем window для хранения, чтобы все content scripts использовали один и тот же Set
 */
const ACTIVE_TOASTS_KEY = '__customToast_activeToasts';

export function getActiveToasts(): Set<ToastInstance> {
  if (!(window as any)[ACTIVE_TOASTS_KEY]) {
    (window as any)[ACTIVE_TOASTS_KEY] = new Set<ToastInstance>();
  }
  return (window as any)[ACTIVE_TOASTS_KEY] as Set<ToastInstance>;
}
