import i18n from 'i18next';
import type { SupportedLanguages } from '../types';
import { getSupportedLanguages } from './getSupportedLanguages';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

export async function languageChangeListenerHandler(
  newLanguage: unknown,
): Promise<void> {
  const { featuresListLocal, featureStore } = await getLocalStorageData([
    LocalStorageKey.FeaturesListLocal,
    LocalStorageKey.FeatureStore,
  ]);
  const featuresList = {
    ...featureStore?.featuresList,
    ...featuresListLocal,
  };
  const supportedLanguages = await getSupportedLanguages(featuresList);
  if (
    typeof newLanguage === 'string' &&
    newLanguage !== i18n.language &&
    supportedLanguages.includes(newLanguage as SupportedLanguages)
  ) {
    void i18n.changeLanguage(newLanguage);
  }
}
