import { getUserCountry } from './getUserCountry';
import { PRIORITY_LANGUAGE } from '../constants';
import { ContextType, SupportedLanguages } from '../types';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

export const getDefaultLocale = async (
  supportedLngs: SupportedLanguages[],
  context: ContextType,
): Promise<SupportedLanguages> => {
  const { currentLocale } = await getLocalStorageData([
    LocalStorageKey.CurrentLocale,
  ]);
  let locale = currentLocale;

  if (!locale && context === 'background') {
    const userCountry = (await getUserCountry()) as
      | SupportedLanguages
      | undefined;

    if (!!userCountry && supportedLngs.includes(userCountry)) {
      locale = userCountry;
    }
  }

  return locale ?? PRIORITY_LANGUAGE;
};
