import { MetaApiData } from '@app/storage/local/types/expirableTypes';
import { getConfigsUrl } from '@utils/getConfigsUrl';
import { configsClient } from './configsClient';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getLocalStorageData } from '@app/storage/local/shared';

export async function fetchMetaApiData(): Promise<MetaApiData> {
  const { isDevMode } = await getLocalStorageData(LocalStorageKey.IsDevMode);

  const metaApiPath = isDevMode
    ? process.env.DEV_META_API_URL
    : process.env.META_API_URL;

  const metaApiUrl = await getConfigsUrl(metaApiPath);

  if (!metaApiUrl) {
    throw new Error('No meta API URL provided');
  }

  const data = await configsClient
    .get<MetaApiData>(metaApiUrl.toString())
    .json();

  const updateMetaApiData: MetaApiData = {
    apiBaseUrl: data.apiBaseUrl,
    cookieDomain: data.cookieDomain,
    currentVersion: data.currentVersion,
    showOnUpdateVersion: data.showOnUpdateVersion,
    proxyUpdatePeriod: data.proxyUpdatePeriod ?? 60 * 6,
    requiredVersion: data.requiredVersion,
    supportedBrowsers: data.supportedBrowsers,
    shouldUpdatePAC: data.shouldUpdatePAC,
    shouldUpdatePACVersion: data.shouldUpdatePACVersion,
    availableBannersData: data.availableBannersData,
    androidAppUrl: data.androidAppUrl,
    availablePaymentMethods: data.availablePaymentMethods,
    availablePaymentMethodsV2: data.availablePaymentMethodsV2,
    availablePaymentMethodsV3: data.availablePaymentMethodsV3,
    publicOfferUrl: data.publicOfferUrl,
    mediaMinVersion: data.mediaMinVersion,
    mediaMaxVersionChrome: data.mediaMaxVersionChrome,
    mediaMaxVersionFirefox: data.mediaMaxVersionFirefox,
    availableAlarmTries: data.availableAlarmTries || 15,
    updateSubscriptionInfoPeriod: data.updateSubscriptionInfoPeriod || 25,
    giftsAvailableDates: data.giftsAvailableDates,
    giftsPeriodInMinutes: data.giftsPeriodInMinutes || 24 * 60,
    rubleToEuroRate: data.rubleToEuroRate,
    beforeStartMediaIntervalInMinutes: data.beforeStartMediaIntervalInMinutes,
    beforeStartMediaUrls: data.beforeStartMediaUrls,
    midpointMediaIntervalInMinutes: data.midpointMediaIntervalInMinutes,
    midpointMediaUrls: data.midpointMediaUrls,
  };

  return { ...data, ...updateMetaApiData };
}
