export enum Feature {
  /**
   * При включенном флаге расширение использует версию пакскрипта Lite (В проекте предусмотрены два варианта PAC-файлов: Full и Lite).
   */
  PACLite = 'pac-lite',

  /** Отключает функциональность автоматического прохождения капчи. */
  CaptchaCrackerDisabled = 'captcha-cracker-disabled',

  /**
   * Включает/выключает показ рекламы от яндекс.
   */
  BannerMedia = 'banner-media',

  /** Отвечает за видимость плашки акции "Черная пятница". */
  BlackFridayOn = 'black-friday-on',

  /**
   * Отвечает за видимость экрана предупреждения <ProxyControlledByOtherExtensions />.
   */
  ProxyControlledByOtherExtensionsVisibility = 'proxy-controlled-by-other-extensions-visibility',

  /**
   * Отвечает за включение режима работы с прокси, требующими авторизации.
   */
  ProxyAuth = 'proxy-auth',

  /**
   * Сбор обратной связи от бесплатных пользователей для улучшения качества продукта.
   */
  FreeUsersReview = 'free-users-review',

  /** Включает/выключает возможность выбора языка в расширении. */
  MultiLocalesSupport = 'multi-locales-support',

  /**
   * Включает/выключает функциональность подарков на странцицах YouTube.
   */
  Gifts = 'gifts',

  /**
   * Отвечает за систему уведомлений (тостов) на страницах YouTube, предупреждающих об истечении подписки.
   */
  SubscriptionExpiringAlerts = 'subscription-expiring-alerts',

  /**
   * Включает показ рекламного видео-преролла перед началом просмотра видео на YouTube (для пользователей без Premium).
   */
  BeforeStartMedia = 'before-start-media',

  /**
   * Включает показ рекламного видео-мидролла через определенные промежутки времени в процессе просмотра видео на YouTube (для пользователей без Premium).
   */
  MidpointMedia = 'midpoint-media',

  /**
   * Позволяет пользователям управлять автопродлением подписки через интерфейс расширения.
   */
  AutoRenewal = 'auto-renewal',

  /**
   * Обеспечивает поддержание активности Service Worker (Manifest V3).
   */
  ServiceWorkerPingPong = 'service-worker-ping-pong',

  /**
   * Включает/выключает проверку доступности прокси при сбоях.
   */
  OnFailDisabledV2 = 'on-fail-disabled-v2',

  /**
   * Включает/выключает автоматическую перезагрузку вкладок YouTube при сетевых ошибках.
   */
  ReloadTabsOnNetworkError = 'reload-tabs-on-network-error',

  /**
   * Включает/выключает отображение рекламного баннера в боковой панели (сайдбаре) YouTube.
   */
  SidebarMedia = 'sidebar-media',

  /**
   * Включает/выключает отображение элементов в поиске яндекса.
   */
  YandexConfig = 'yandex-config',

  /**
   * Включает/выключает отображение "красной кнопки" на главной странице вместо кнопки TelegramPromo.
   */
  RedButton = 'red-button',
}

export type FeatureList = {
  [Feature.PACLite]: boolean;
  [Feature.CaptchaCrackerDisabled]: boolean;
  [Feature.BannerMedia]: boolean;
  [Feature.BlackFridayOn]: boolean;
  [Feature.ProxyControlledByOtherExtensionsVisibility]: boolean;
  [Feature.ProxyAuth]: boolean;
  [Feature.FreeUsersReview]: boolean;
  [Feature.MultiLocalesSupport]: boolean;
  [Feature.Gifts]: boolean;
  [Feature.SubscriptionExpiringAlerts]: boolean;
  [Feature.BeforeStartMedia]: boolean;
  [Feature.MidpointMedia]: boolean;
  [Feature.AutoRenewal]: boolean;
  [Feature.ServiceWorkerPingPong]: boolean;
  [Feature.OnFailDisabledV2]: boolean;
  [Feature.ReloadTabsOnNetworkError]: boolean;
  [Feature.SidebarMedia]: boolean;
  [Feature.YandexConfig]: boolean;
  [Feature.RedButton]: boolean;
};

export type FeatureListResponse = {
  [Feature.PACLite]: string;
  [Feature.CaptchaCrackerDisabled]: string;
  [Feature.BannerMedia]: string;
  [Feature.BlackFridayOn]: string;
  [Feature.ProxyControlledByOtherExtensionsVisibility]: string;
  [Feature.ProxyAuth]: string;
  [Feature.FreeUsersReview]: string;
  [Feature.MultiLocalesSupport]: string;
  [Feature.Gifts]: string;
  [Feature.SubscriptionExpiringAlerts]: string;
  [Feature.BeforeStartMedia]: string;
  [Feature.MidpointMedia]: string;
  [Feature.AutoRenewal]: string;
  [Feature.ServiceWorkerPingPong]: string;
  [Feature.OnFailDisabledV2]: string;
  [Feature.ReloadTabsOnNetworkError]: string;
  [Feature.SidebarMedia]: string;
  [Feature.YandexConfig]: string;
  [Feature.RedButton]: string;
};

export type FeatureStore = {
  isInitialized: boolean;
  featuresList: FeatureList;
  loading: boolean;
  error: Error | null;
};

export function isFeatureStore(value: unknown): value is FeatureStore {
  return (
    typeof value === 'object' &&
    value !== null &&
    'featuresList' in value &&
    typeof (value as any).featuresList === 'object'
  );
}
