import { fetchUserCountry } from '@api/fetchUserCountry';
import { getMetaApiData } from '@utils/metaApiData';
import { logger } from '@utils/logger';

export const getUserCountry = async () => {
  try {
    const { apiBaseUrl } = await getMetaApiData();
    const response = await fetchUserCountry({ apiBaseUrl });

    return response.country;
  } catch (error) {
    logger.error('getUserCountry: error', error);
    return null;
  }
};
